# 決定可能・ℝ 不使用。極限のみが ℝ 側。

# スピン1 行列。Sx,Sy は √2,i を含むが S·S は有理。QQbar で組んで有理係数を確認。
r2 = QQbar(_sage_const_2 ).sqrt()
I_ = QQbar(I)
Sx = (_sage_const_1 /r2)*matrix(QQbar,[[_sage_const_0 ,_sage_const_1 ,_sage_const_0 ],[_sage_const_1 ,_sage_const_0 ,_sage_const_1 ],[_sage_const_0 ,_sage_const_1 ,_sage_const_0 ]])
Sy = (_sage_const_1 /r2)*matrix(QQbar,[[_sage_const_0 ,-I_,_sage_const_0 ],[I_,_sage_const_0 ,-I_],[_sage_const_0 ,I_,_sage_const_0 ]])
Sz = matrix(QQbar,[[_sage_const_1 ,_sage_const_0 ,_sage_const_0 ],[_sage_const_0 ,_sage_const_0 ,_sage_const_0 ],[_sage_const_0 ,_sage_const_0 ,-_sage_const_1 ]])
I3 = identity_matrix(QQbar,_sage_const_3 )

def emb(op,i,N):
    mats=[op if k==i else I3 for k in range(N)]
    M=mats[_sage_const_0 ]
    for k in range(_sage_const_1 ,N):
        M=M.tensor_product(mats[k])
    return M

def dot_two_site(i,j,N):
    return emb(Sx,i,N)*emb(Sx,j,N)+emb(Sy,i,N)*emb(Sy,j,N)+emb(Sz,i,N)*emb(Sz,j,N)

def H_BT(N):
    dim=_sage_const_3 **N
    H=matrix(QQbar,dim,dim)
    for j in range(N):
        jp=(j+_sage_const_1 )%N
        SS=dot_two_site(j,jp,N)
        H += SS - SS*SS
    # S·S 由来は有理 ⇒ H を QQ へ coerce 可能か確認しつつ返す
    return H

